SELECT ?club ?clubLabel WHERE {
  wd:Q184586 p:P54 ?statement.
  ?statement ps:P54 ?club.
  ?statement pq:P2390 wd:Q54501.
  ?statement pq:P580 ?start.
  ?statement pq:P582 ?end.
  FILTER ( ?start <= "2020-12-31T23:59:59"^^xsd:dateTime && ?end >= "2020-01-01T00:00:00"^^xsd:dateTime )
  OPTIONAL { ?club rdfs:label ?clubLabel. FILTER (lang(?clubLabel) = "en") }
}

